import { z } from "zod";

export const registrationSchema = z.object({
  username: z.string().min(3, "Username must be at least 3 characters"),
  email: z.string().email("Invalid email format").min(1, "Email is required"),
  role: z.enum(["user", "admin", "contributor"]),
  otherInfo: z.string().optional(),
  newsletter: z.boolean().optional(),
  frequency: z.enum(["daily", "weekly", "monthly"]).optional(),
  bio: z.string().optional(),
}).superRefine((data, ctx) => {
  // otherInfo is required when role is "contributor"
  if (data.role === "contributor" && !data.otherInfo) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      message: "Other info is required for contributors",
      path: ["otherInfo"],
    });
  }

  // frequency is required when newsletter is true
  if (data.newsletter && !data.frequency) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      message: "Frequency is required when newsletter is selected",
      path: ["frequency"],
    });
  }
});

export type RegistrationFormValues = z.infer<typeof registrationSchema>;

export const registrationInitialValues: RegistrationFormValues = {
  username: "",
  email: "",
  role: "user",
  otherInfo: "",
  newsletter: false,
  frequency: undefined,
  bio: "",
};

import { z } from "zod";

/**
 * Registration form schema with conditional validation.
 *
 * Patterns:
 * - .superRefine() for cross-field conditional validation
 * - Conditional fields: otherInfo (contributor), frequency (newsletter)
 */
export const registrationSchema = z.object({
  username: z.string().min(3, "Username must be at least 3 characters"),
  email: z.string().email("Invalid email format").min(1, "Email is required"),
  role: z.enum(["user", "admin", "contributor"]),
  // otherInfo is optional by default; required for contributor via superRefine
  otherInfo: z.string().optional(),
  // newsletter enables the frequency field
  newsletter: z.boolean().optional(),
  // frequency is optional; required only when newsletter is true
  frequency: z.enum(["daily", "weekly", "monthly"]).optional(),
  // bio is always optional
  bio: z.string().optional(),
}).superRefine((data, ctx) => {
  // otherInfo is required when role is "contributor"
  if (data.role === "contributor" && !data.otherInfo) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      message: "Other info is required for contributors",
      path: ["otherInfo"],
    });
  }

  // frequency is required when newsletter is true
  if (data.newsletter === true && !data.frequency) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      message: "Please select a frequency",
      path: ["frequency"],
    });
  }
});

export type RegistrationFormValues = z.infer<typeof registrationSchema>;

/**
 * Initial values for the registration form.
 * All fields must be included to match the schema structure.
 */
export const registrationInitialValues: RegistrationFormValues = {
  username: "",
  email: "",
  role: "user",
  otherInfo: "",
  newsletter: false,
  frequency: undefined,
  bio: "",
};

